#include <stdio.h>
int main() {
    int T, N, Q, type, L, R, X, Y;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &Q);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        while (Q--) {
            scanf("%d %d %d", &type, &L, &R);
            if (type == 1) {
                int maxVal = 0;
                for (int M = L - 1; M <= R - 1; M++) {
                    int val = (A[M] - A[L - 1]) * (A[R - 1] - A[M]);
                    if (val > maxVal) {
                        maxVal = val;
                    }
                }
                printf("%d\n", maxVal);
            } else if (type == 2) {
                scanf("%d", &Y);
                A[L - 1] = Y;
            }
        }
    }
    return 0;
}

