import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            while (Q-- > 0) {
                int type = sc.nextInt();
                int L = sc.nextInt();
                int R = sc.nextInt();
                if (type == 1) {
                    int maxVal = 0;
                    for (int M = L - 1; M <= R - 1; M++) {
                        int val = (A[M] - A[L - 1]) * (A[R - 1] - A[M]);
                        if (val > maxVal) {
                            maxVal = val;
                        }
                    }
                    System.out.println(maxVal);
                } else if (type == 2) {
                    int Y = sc.nextInt();
                    A[L - 1] = Y;
                }
            }
        }
    }
}

